#!/usr/bin/env node

import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { createCipheriv, createDecipheriv, randomBytes } from "node:crypto";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const envPath = join(__dirname, "..", "..", ".env");
const dbPath = join(__dirname, "..", "..", "data", "discord_bot.db");

// Self-defined tokens — generated by us, rotated by this script.
// Each entry declares its byte-length + encoding per its consumer's algorithm.
//
// API_TOKEN              — opaque bearer for inter-process auth (server ↔ discord ↔ plugin-api).
//                          48 bytes base64url for URL/header safety. Verified at
//                          main/server/src/api/middleware.ts:18.
// DISCORD_TOKEN_ENC_KEY  — AES-256-GCM master key encrypting BYO discord bot tokens AND
//                          discord_interactions_pending tokens. EXACTLY 32 bytes base64.
//                          Verified at main/server/src/crypto/master-key-loader.ts.
const API_TOKEN_BYTES = 48;
const AES_256_KEY_BYTES = 32;
const AES_GCM_IV_BYTES = 12;
const AES_GCM_AUTH_TAG_BYTES = 16;
const AES_GCM_ALGORITHM = "aes-256-gcm";

function encryptToken(plaintext, masterKey) {
  const iv = randomBytes(AES_GCM_IV_BYTES);
  const cipher = createCipheriv(AES_GCM_ALGORITHM, masterKey, iv);
  const ct = Buffer.concat([cipher.update(plaintext, "utf-8"), cipher.final()]);
  const tag = cipher.getAuthTag();
  return { b64: Buffer.concat([ct, tag]).toString("base64"), iv: iv.toString("base64") };
}

function decryptToken(b64, ivB64, masterKey) {
  const buf = Buffer.from(b64, "base64");
  const ct = buf.subarray(0, buf.length - AES_GCM_AUTH_TAG_BYTES);
  const tag = buf.subarray(buf.length - AES_GCM_AUTH_TAG_BYTES);
  const iv = Buffer.from(ivB64, "base64");
  const decipher = createDecipheriv(AES_GCM_ALGORITHM, masterKey, iv);
  decipher.setAuthTag(tag);
  return Buffer.concat([decipher.update(ct), decipher.final()]).toString("utf-8");
}

function readOldMasterKey(envContent) {
  const match = envContent.match(/^DISCORD_TOKEN_ENC_KEY=(.*)$/m);
  if (!match || !match[1]) return null;
  const buf = Buffer.from(match[1], "base64");
  return buf.length === AES_256_KEY_BYTES ? buf : null;
}

function upsertEnvLine(content, name, value) {
  const pattern = new RegExp(`^${name}=.*$`, "m");
  if (pattern.test(content)) return content.replace(pattern, `${name}=${value}`);
  const sep = content.length === 0 || content.endsWith("\n") ? "" : "\n";
  return `${content}${sep}${name}=${value}\n`;
}

// Phase 1 — read current .env (may not exist; greenfield is fine)
let envContent = "";
try {
  envContent = readFileSync(envPath, "utf-8");
} catch {
  envContent = "";
}
const oldMasterKey = readOldMasterKey(envContent);

// Phase 2 — generate new tokens
const newApiToken = randomBytes(API_TOKEN_BYTES).toString("base64url");
const newMasterKey = randomBytes(AES_256_KEY_BYTES);
const newMasterKeyB64 = newMasterKey.toString("base64");

// Phase 3 — re-encrypt BYO bot rows + interactions in a transaction; clear unrecoverable rows
let reencryptedBots = 0;
let clearedBots = 0;
let droppedInteractions = 0;

if (existsSync(dbPath)) {
  const { default: Database } = await import("better-sqlite3");
  const db = new Database(dbPath);
  try {
    db.pragma("busy_timeout = 3000");

    const identitiesTable = db
      .prepare(`SELECT name FROM sqlite_master WHERE type = 'table' AND name = 'discord_bot_identities'`)
      .get();
    if (!identitiesTable) {
      db.close();
      console.log("data/discord_bot.db exists but has no discord_bot_identities table — skipping db work.");
      const out = upsertEnvLine(upsertEnvLine(envContent, "API_TOKEN", newApiToken), "DISCORD_TOKEN_ENC_KEY", newMasterKeyB64);
      writeFileSync(envPath, out, "utf-8");
      console.log(`API_TOKEN rotated              → ${newApiToken.slice(0, 8)}...${newApiToken.slice(-4)}`);
      console.log(`DISCORD_TOKEN_ENC_KEY rotated  → ${newMasterKeyB64.slice(0, 8)}...${newMasterKeyB64.slice(-4)}`);
      process.exit(0);
    }

    const botRows = db
      .prepare(
        `SELECT bot_id, encrypted_token_b64, token_iv_b64 FROM discord_bot_identities WHERE encrypted_token_b64 IS NOT NULL`,
      )
      .all();

    const reencryptBot = db.prepare(
      `UPDATE discord_bot_identities SET encrypted_token_b64 = ?, token_iv_b64 = ? WHERE bot_id = ?`,
    );
    const clearBot = db.prepare(
      `UPDATE discord_bot_identities SET encrypted_token_b64 = NULL, token_iv_b64 = NULL WHERE bot_id = ?`,
    );

    // Re-encrypt in memory first — only commit if every row succeeds OR every failure is clearable
    const planned = [];
    for (const row of botRows) {
      if (!oldMasterKey) {
        planned.push({ kind: "clear", bot_id: row.bot_id });
        continue;
      }
      try {
        const plaintext = decryptToken(row.encrypted_token_b64, row.token_iv_b64, oldMasterKey);
        const re = encryptToken(plaintext, newMasterKey);
        planned.push({ kind: "reencrypt", bot_id: row.bot_id, b64: re.b64, iv: re.iv });
      } catch {
        planned.push({ kind: "clear", bot_id: row.bot_id });
      }
    }

    const tx = db.transaction(() => {
      for (const p of planned) {
        if (p.kind === "reencrypt") {
          reencryptBot.run(p.b64, p.iv, p.bot_id);
          reencryptedBots++;
        } else {
          clearBot.run(p.bot_id);
          clearedBots++;
        }
      }
      const interactionsTable = db
        .prepare(`SELECT name FROM sqlite_master WHERE type = 'table' AND name = 'discord_interactions_pending'`)
        .get();
      if (interactionsTable) {
        const cleanup = db.prepare(`DELETE FROM discord_interactions_pending`).run();
        droppedInteractions = cleanup.changes;
      }
    });
    tx();
  } finally {
    db.close();
  }
}

// Phase 4 — write the new .env (db is already updated; this is the commit point for the rotation)
let updated = envContent;
updated = upsertEnvLine(updated, "API_TOKEN", newApiToken);
updated = upsertEnvLine(updated, "DISCORD_TOKEN_ENC_KEY", newMasterKeyB64);
writeFileSync(envPath, updated, "utf-8");

// Summary
console.log(`API_TOKEN rotated              → ${newApiToken.slice(0, 8)}...${newApiToken.slice(-4)}`);
console.log(`DISCORD_TOKEN_ENC_KEY rotated  → ${newMasterKeyB64.slice(0, 8)}...${newMasterKeyB64.slice(-4)}`);
if (reencryptedBots > 0) console.log(`BYO bot rows re-encrypted with new key: ${reencryptedBots}`);
if (clearedBots > 0)
  console.log(`BYO bot rows cleared (old key absent or unrecoverable): ${clearedBots}`);
if (droppedInteractions > 0)
  console.log(`Pending interaction rows cleared (15-min TTL, will rebuild from gateway): ${droppedInteractions}`);
console.log("");
console.log("⚠ If server/discord/ were running during rotation, restart them so handles re-read .env.");
